commands.examples:
SELECT COUNT(*) FROM users;
SELECT COUNT(DISTINCT city) FROM users;
SELECT SUM(total) AS revenue FROM orders WHERE status = 'paid';
SELECT AVG(price) AS avg_price FROM products;
SELECT role, COUNT(*) AS total FROM users GROUP BY role;

SELECT MIN(price), MAX(price) FROM products;
SELECT category_id, MIN(price) AS cheapest, MAX(price) AS most_expensive
FROM products GROUP BY category_id;

SELECT user_id, GROUP_CONCAT(product_name) AS products
FROM orders GROUP BY user_id;

SELECT category,
  GROUP_CONCAT(DISTINCT name ORDER BY price DESC SEPARATOR ' | ') AS products
FROM products GROUP BY category;
